import faicons as fa
import pandas as pd
import plotly.express as px
import numpy as np
import io
from shared import app_dir, df_repindata, data_dicty, cv_collection, cv_columns,cv_resourceType, cv_themes, cv_region, cv_language, pub_min, pub_max
from utils.website_texts import about_text, data_dictionary

from shinywidgets import output_widget, render_plotly
from shiny import App, reactive, render, ui
import shinyswatch


ICONS = {
    "table":fa.icon_svg("table-list"),
    "calculator": fa.icon_svg("calculator"),
    "clock": fa.icon_svg("clock")
}

app_ui = ui.page_sidebar(
    ui.sidebar(
        ui.include_css(app_dir / "www/style.css"),

        ui.input_selectize(
            "select_themes",
            "Select theme",
            cv_themes,
            multiple=False,
            selected="All"
        ),
        ui.input_selectize(
            "select_region",
            "Select region(s)",
            cv_region,
            multiple=True,
            selected="All"
        ),
        ui.input_slider(
            "select_pub_year", 
            "Publication year(s)", 
            min=pub_min, 
            max=pub_max,
            value=[pub_min,pub_max],
            sep = "",
            ),        

        ui.input_selectize(
            "select_lang",
            "Select language(s)",
            cv_language,
            multiple=True,
            selected="All"
        ),
        ui.input_text("free_text", "Search for text", "Enter text..."),   
        ui.input_selectize(
            "select_retype",
            "Select a Resource Type",
            cv_resourceType,
            selected="All"
        ),
        ui.input_selectize(
            "select_collect",
            "Select a Collection",
            cv_collection,
            selected="All"
        ),
        bg="#f8f8f8"),  
    ui.navset_pill(  
        ui.nav_panel("Overview",
                     ui.layout_column_wrap(
                         ui.card(about_text),
                         fill=False,), 
                     ui.layout_column_wrap(
                         ui.value_box("Number of resources in this selection",ui.output_text("selected_entries")),

                    fill=False,),
                    ui.layout_column_wrap(
                        ui.card("Top resource types in selection",
                                ui.navset_card_tab(

                                    ui.nav_panel("Table",ui.output_data_frame("top_resourcetypes")),
                                    ui.nav_panel("Chart",output_widget("retype_bar") ),
                                ),
                               ),
                        ui.card("Top regions in selection", 
                                ui.navset_card_tab(
                                    ui.nav_panel("Table",ui.output_data_frame("top_regions")),
                                    ui.nav_panel("Chart",output_widget("regions_pie"))
                                ),
                                ), 

                    fill=False),
                     ),
        ui.nav_panel("Explore resources", 
                     ui.layout_columns(
                         ui.card(

                              ui.card_header("Resources overview"),
                              ui.div(
                                  ui.input_selectize(
                                      "select_columns",
                                      "Select columns to display",
                                      cv_columns,
                                      multiple=True,
                                      selected=["Title","PubDate","URL"],
                                      width='45%'
                                  ),
                                  ui.download_button("download_filtered", label="Download filtered data as .csv", class_="btn-primary"),
                                  ui.input_action_button("grid_details","Show details for selected row", class_="btn-primary")),

                              ui.output_data_frame("grid_table"),                              
                          ),

                    ),

                    ),
        ui.nav_panel("About the data explorer",
                     ui.layout_columns(
                         ui.card(data_dictionary,
                                 ui.output_data_frame("data_dict")

                         )

                     ),

        ),


        id="tab"
    ),
    theme=shinyswatch.theme.lux,
    window_title="Representation in data",
    title=ui.tags.div(ui.tags.p(ui.tags.img(src="logo.png", height="40px"), "   IASSIST Representation in Data Explorer")),
    )

def server(input, output, session):
    # internal links between tabs
    @reactive.effect
    @reactive.event(input.goto_explore)
    def _():
        ui.update_navs("tab", selected="Explore resources")

    @reactive.effect
    @reactive.event(input.goto_about)
    def _():
        ui.update_navs("tab", selected="About the data explorer")

    @reactive.calc
    def filtered_data():
        # filter for Collection
        if input.select_collect() == "All":
            filt_collection = (df_repindata["Collection"]!= "All") | (df_repindata["Collection"].isnull())
        else:
            filt_collection = (df_repindata["Collection"].notnull()) & (df_repindata["Collection"].str.contains(input.select_collect()))


        # filter for the ResourceType
        if input.select_retype() == "All":
            filt_resourcetype = (df_repindata["ResourceType"]!= "All") | (df_repindata["ResourceType"].isnull())
        else:
            filt_resourcetype = (df_repindata["ResourceType"].notnull()) & (df_repindata["ResourceType"].str.contains(input.select_retype()))

        # filter for PubYear
        filt_pubyear = (df_repindata["PubDate"].isnull()) | (df_repindata["PubDate"].between(input.select_pub_year()[0],input.select_pub_year()[1]))

        # filter for Theme
        if input.select_themes() == "All":
            filt_themes = (df_repindata["Themes"] != "All") | (df_repindata["Themes"].isnull())
        else:
            filt_themes = (df_repindata["Themes"].notnull()) & (df_repindata["Themes"].str.contains(input.select_themes()))

        # filter for language
        if ''.join(input.select_lang()) == "All":
            filt_lang = (df_repindata["Language"] != "All") | (df_repindata["Language"].isnull())
        else:
            filt_lang = (df_repindata["Language"].notnull()) & (df_repindata["Language"].isin(list(input.select_lang())))

        # filter for Region
        if ''.join(input.select_region()) == "All":
            filt_region = (df_repindata["GeographicRegion"] != "All") | (df_repindata["GeographicRegion"].isnull())
        else:
            filt_region = (df_repindata["GeographicRegion"].notnull()) & (df_repindata["GeographicRegion"].isin(list(input.select_region())))
        # free text input
        if input.free_text() == "Enter text...":
            filt_free = (df_repindata["GeographicRegion"] !="All") | (df_repindata["GeographicRegion"].isnull())
        else:
            filt_free = (df_repindata.apply(lambda row: row.astype(str).str.contains(input.free_text()).any(), axis=1))

        return df_repindata.loc[filt_collection & filt_resourcetype & filt_themes & filt_region & filt_free & filt_lang & filt_pubyear]

    @render.text
    def selected_entries():
        return filtered_data().shape[0]

    @render.data_frame
    def top_resourcetypes():
        top_restypes = pd.DataFrame(filtered_data()["ResourceType"].value_counts().head(10))
        top_restypes.reset_index(drop=False, inplace=True)
        top_restypes.rename(columns={"ResourceType":"Resource Type"}, inplace=True)
        return render.DataGrid(top_restypes) 

    @render_plotly
    def retype_bar():
        top_restypes = pd.DataFrame(filtered_data()["ResourceType"].value_counts().head(10))
        top_restypes.reset_index(drop=False, inplace=True)
        top_restypes.rename(columns={"ResourceType":"Resource Type"}, inplace=True)
        retypes_fig = px.bar(top_restypes, "Resource Type", "count")
        return retypes_fig

    @render.data_frame
    def top_regions(): 
        top_regs = pd.DataFrame(filtered_data()["GeographicRegion"].value_counts().head(10))
        top_regs.reset_index(drop=False, inplace=True)
        top_regs.rename(columns={"GeographicRegion":"Region"}, inplace=True)
        return render.DataGrid(top_regs)

    @render_plotly
    def regions_pie():
        top_regs = pd.DataFrame(filtered_data()["GeographicRegion"].value_counts().head(10))
        top_regs.reset_index(drop=False, inplace=True)
        top_regs.rename(columns={"GeographicRegion":"Region"}, inplace=True)
        regs_fig = px.pie(top_regs, values='count', names='Region')
        return regs_fig

# create the spreadsheet for "Explore resources" tab
    @render.data_frame 
    def grid_table():
        cols = list(input.select_columns())
        cols.append("ID")


        return render.DataGrid(filtered_data()[cols], 
                                selection_mode="row", 
                                filters=False,
                                summary=False)

# details on the selected resource
    @render.text
    def grid_detail_description():
        selected = grid_table.data_view(selected=True)["ID"]-1
        description = df_repindata.loc[selected,"Description"].sum()
        return description

    @render.ui
    def grid_detail_url():
        selected = grid_table.data_view(selected=True)["ID"]-1
        url = df_repindata.loc[selected,"URL"].sum()
        return ui.a(f"{url}",href=f"{url}", target="_blank")

    @render.ui
    def grid_detail_dates():
        selected = grid_table.data_view(selected=True)["ID"]-1
        start = df_repindata.loc[selected,"CollectDateStart"].astype(int).sum()
        end = df_repindata.loc[selected,"CollectDateEnd"].astype(int).sum()
        span = df_repindata.loc[selected,"TimeSpan"].sum()
        longitudinal = df_repindata.loc[selected,"Longitudinal"].sum()
        return ui.div(ui.p(f"Longitudinal? {longitudinal}"),ui.p(f"Data collection: {str(start)} - {str(end)}"), ui.p(f"Temporal coverage: {span}"))

    @render.ui
    def grid_detail_geoadmin():
        selected = grid_table.data_view(selected=True)["ID"]-1
        country = df_repindata.loc[selected,"Country"].sum()
        region = df_repindata.loc[selected,"GeographicRegion"].sum()
        admin = df_repindata.loc[selected,"AdminLevel"].sum()
        return ui.div(ui.p(f"Country: {country}"), ui.p(f"Geographic region: {region}"), ui.p(f"Administrative level: {admin}"))

    @render.ui
    def grid_detail_method():
        selected = grid_table.data_view(selected=True)["ID"]-1
        method = df_repindata.loc[selected,"DataMethodType"].sum()
        unit = df_repindata.loc[selected,"UnitAnalysis"].sum()
        return ui.div(ui.p(f"Methods: {method}"),ui.p(f"Unit of analysis: {unit}"))

    @render.ui
    def grid_detail_themes():
        selected = grid_table.data_view(selected=True)["ID"]-1
        themes = df_repindata.loc[selected,"Themes"].sum()
        subjects = df_repindata.loc[selected,"Subjects"].sum()
        return ui.div(ui.p(f"Themes: {themes}"),ui.p(f"Subjects: {subjects}"))

    @render.ui
    def grid_detail_further():
        selected = grid_table.data_view(selected=True)["ID"]-1
        producer = df_repindata.loc[selected,"Producer"].sum()
        distributor = df_repindata.loc[selected,"Distributor"].sum()
        restrictions = df_repindata.loc[selected,"Restrictions"].sum()
        notes = df_repindata.loc[selected,"Notes"].sum()
        return ui.div(ui.p(f"Producer: {producer}"),ui.p(f"Distributor: {distributor}"),ui.p(f"Restrictions? {restrictions}"),ui.p(f"Note: {notes}"))





# details popup
    @reactive.effect
    @reactive.event(input.grid_details)
    def _():
        m = ui.modal(
            ui.accordion(
                ui.accordion_panel("URL",ui.output_ui("grid_detail_url")),
                ui.accordion_panel("Description",ui.output_text("grid_detail_description")),
                ui.accordion_panel("Methods", ui.output_ui("grid_detail_method")),
                ui.accordion_panel("Geographic coverage and administrative level",ui.output_ui("grid_detail_geoadmin")),
                ui.accordion_panel("Collection dates and coverage",ui.output_ui("grid_detail_dates")),
                ui.accordion_panel("Themes and subjects",ui.output_ui("grid_detail_themes")),
                ui.accordion_panel("Further notes",ui.output_ui("grid_detail_further"))



            ),

            title="Details for selected resource",
            easy_close=True,
            footer=None,
        )
        ui.modal_show(m)

# download of a filtered csv button
    @render.download(filename="output.csv")
    def download_filtered():
        data = grid_table.data_view()
        with io.BytesIO() as buf:
                data.to_csv(buf,header=True, index=False,encoding="utf-8")
                yield buf.getvalue() 

# create the data dictionary spreadsheet
    @render.data_frame
    def data_dict():
        data_dicty["Link"] = [
            ui.tags.a("Representation in Data",href=f"https://docs.google.com/spreadsheets/d/1b9ODZxyBzDPfwono_FNJ0N-M3yXlWP8TXbCZXAeVqrQ/edit?{sheet}",target="_blank") for sheet in data_dicty["Link to CV"]
            ]
        return render.DataGrid(data_dicty[["Field Names","Description"]], width="100%")



app = App(app_ui, server, static_assets=app_dir / "www")

